  (86, 'MaN_Zrodlo',        'Powiązanie z dokumentem źródłowym',    '0, 1',                      'Powiazanie_Zrodlowe',                 'CASE MaN_Zrodlo WHEN 0 THEN ''Niepowiązany'' WHEN 1 THEN ''Powiązany'' WHEN 2 THEN ''Powiązany wielokrotnie'' ELSE ''Nieznane ('' + CAST(MaN_Zrodlo AS VARCHAR) + '')'' END',                                                                                                                                             'Tak',  '',                              ''),
  (87, 'MaN_RezerwujZasoby','Rezerwuj zasoby (WMS)',                 '',                          NULL,                                 NULL,                                                                                                                                                                                                                                                                                                                      'Nie',  'is_useful=Nie w dokumentacji',  ''),
  (88, 'MaN_WMSDokWewn',    'Wystawianie dok. WMS dla MMW/MMP',     '',                          NULL,                                 NULL,                                                                                                                                                                                                                                                                                                                      'Nie',  'is_useful=Nie w dokumentacji',  ''),
  (89, 'MaN_WZWMPelneJPom', 'Wymuś pełne ilości w J.pom.',          '',                          NULL,                                 NULL,                                                                                                                                                                                                                                                                                                                      'Nie',  'is_useful=Nie w dokumentacji',  ''),
  (90, 'MaN_KolejnoscZal',  'Kolejność załadunku',                   '',                          NULL,                                 NULL,                                                                                                                                                                                                                                                                                                                      'Nie',  'is_useful=Nie w dokumentacji',  ''),
  (91, 'MaN_LaczPozycje',   'Agregacja pozycji w partii',            '',                          NULL,                                 NULL,                                                                                                                                                                                                                                                                                                                      'Nie',  'is_useful=Nie w dokumentacji',  '')
) AS t(Kolejnosc, CDN_Pole, Opis_w_dokumentacji, Przykladowe_wartosci, Alias_w_widoku, Transformacja, Uwzglednic, Uzasadnienie, Komentarz_Analityka)
